var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음……. 슬슬 배달 시간이 다 됐는데…….","JPN":"ふむ……そろそろ配達の時間だが。","ENG":"Hm... The delivery should be here any minute...","TWN":"嗯…差不多快送到了吧…"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님, 그 계획 정말 진행하실 건가요?","JPN":"社長、本当にその計画でいいんでしょうか？","ENG":"Boss, are you sure you want to proceed with the plan?","TWN":"老闆，你確定要執行那個計畫嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"골칫거리를 해결하려고 더 큰 골칫거리들을 불러들인다는 느낌이 드는군요.","JPN":"悩みの種を解決するために、さらに厄介なものを巻き込んでいる気がします。","ENG":"I feel like you’re calling in a bigger problem to solve a smaller one.","TWN":"有種反而會把事情鬧大的感覺。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"후후, 직원이 인재가 될지 짐이 될지는 쓰는 사람에 따라 정해진다네, 부사장.","JPN":"フフ、社員が人材になるか荷物になるかは、使う人によって決まるものだ、副社長。","ENG":"Hah hah, employee performance depends on the employer, Vice President.","TWN":"呵呵，我說副總，部下會成為人才還是蠢材，是由領袖決定的。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주인님~! 펭귄들이 마을로 엄청 몰려오고 있슴다!","JPN":"ご主人様ー！　ペンギンたちが村に向かって押しよせて来たっす！","ENG":"Master! A horde of penguins is approaching our town!","TWN":"主人～！很多企鵝正朝村子衝過來唷！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네?","JPN":"モネ？","ENG":"Mone?","TWN":"莫妮？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네!","JPN":"モネネ！","ENG":"Monene!","TWN":"莫妮妮！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오오, 망 보느라 고생했네. 모네 양.","JPN":"おお、見張りご苦労さま、モネ。","ENG":"Oh, good job watching out for us, Mone.","TWN":"好喔，謝謝你的通知。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그런데 쟤네들로 뭘 할 생각이심까? 주인님도 허리가 아프심까?","JPN":"ところであの子たちで何をするつもりっすか？　ご主人様も腰が痛いっすか？","ENG":"What are you going to do with them, sir? You have back pain as well?","TWN":"不過主人想拿他們想做什麼呢？主人腰痠嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어흠. 아직 그럴 나이는 아닐세.","JPN":"えっへん。まだそんな歳ではないぞ。","ENG":"Oh, I’m not that old.","TWN":"咳咳，我還沒到那個年紀啦。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"저기 예거 양도 돌아오는군. 모여서 얘기하면 되겠어.","JPN":"ちょうどイェーガーさんが戻ってきたようだな。集まって話そう。","ENG":"There comes Ms. Jaegar. We should gather up and discuss the plan.","TWN":"伊格也回來了，大家先集合再說吧。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"기다리셨죠! 부탁하신 인원들 정시 도착했습니다!","JPN":"お待たせしました！　頼まれた社員、全員定時到着しました！","ENG":"Thank you for waiting. I brought the ones you requested on time!","TWN":"久等了！你要的人都準時送達囉！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L24_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"저, 저 분들은……?","JPN":"あ、あの方たちは……？","ENG":"Th-they are...","TWN":"那…那些人是…？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"후후. 한눈에 알아보는군, 모네 양.","JPN":"フフ、気付いたか、モネ。","ENG":"Heh heh. You do recognize them, Mone.","TWN":"呵呵，你一眼就認出來了吧？！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"마을의 문제를 해결하기 위해 코핀 컴퍼니에서 부른 해결사 삼총사다!","JPN":"村の問題を解決するためにコフィンカンパニーから精鋭三銃士を連れて来た！","ENG":"They are the fixer trio from Coffin Company!","TWN":"這是我從科芬公司請來解決村子問題的終結者三劍客。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L29_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"해결사 삼총사……?","JPN":"精鋭三銃士っすか……？","ENG":"The fixer trio?","TWN":"終結者三劍客…？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이쪽은 시그마, 우리 귀여운 딸내미지.","JPN":"こちらはシグマ、我が可愛い娘だ。","ENG":"This is Sigma, my beloved daughter.","TWN":"這位是西格瑪，是我的可愛女兒。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아빠! 나 아빠 없는 동안 회사 잘 지키고 있었다? 잘했지?","JPN":"パパ！　パパがいない間会社を守っていたの！　イイ子でしょ？","ENG":"Daddy! I’ve been watching the company while you were gone. I did well, didn't I?","TWN":"爸爸！爸爸不在的時候我有好好看著公司喔，我很棒吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그리고 세리나 크루 양. 우리 회사 편의점 견습 아르바이트생이라네.","JPN":"そしてセリーナ・クルー。我が社のコンビニの見習いアルバイトだ。","ENG":"And this is Serina Crew. Probationary part-timer at the company convenience store.","TWN":"還有瑟琳娜，是我們公司便利商店的實習工讀生。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"매출 올려 주신다면서요, 사장님?","JPN":"売上を上げてくださると聞いて来ましたよ、社長！","ENG":"Boss, you said you were ready to promote our sales!","TWN":"老闆你不是說要提高銷售額嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"바닷가라고 하셔서 새로 입고된 수영복도 꺼내 왔어요♬ 기대하고 있을게요?","JPN":"リゾート地と聞いて新しく入荷した水着も持ってきました♬　楽しみにしています！","ENG":"I heard we were going to a beach, so I brought a new swimsuit from our stock. ♬ I hope we have a good time!","TWN":"你叫我來海邊，我就順便把新到貨的泳衣也拿來囉♬ 好期待喔～"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네 안 잘리는 것도 참 신기하구만…….","JPN":"君はあのコンビニから首にならないのが実に不思議だな……","ENG":"It’s a wonder you’re not fired...","TWN":"你沒被開除也真神奇…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"마지막으로…….","JPN":"最後に……","ENG":"Now, last but not least...","TWN":"最後…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"훗훗. 해결사로 날 찾다니 조심해야 할 거야.","JPN":"フッフッ、フィクサーとしてこの私を招くとは。リスキーだな。","ENG":"Heh heh. You should be careful when looking for me as a fixer.","TWN":"呵呵，找我來終結問題嗎？要小心囉～"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"내 총알은 단 하나의 해결책밖에 모르거든.","JPN":"私の弾丸はたった一つのやり方しか知らないからな。","ENG":"My bullets know only one answer.","TWN":"我的子彈只有一種解決方案喔。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"……뉘, 뉘신지?","JPN":"……だ、誰だっけ？","ENG":"... W-who are you?","TWN":"…請問…你哪位？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"이 몸의 이름은 바로 린 시엔! 화약 냄새를 따라 떠도는 나그네지!","JPN":"我が名はリン・シエン！　火薬の匂いに導かれて彷徨う旅人である！","ENG":"I am Lin Xien! I am a wanderer who follows the smell of gunpowder!","TWN":"我叫林·西恩！是逐火藥味而居的浪子！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L49_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"저희 편의점에 온 임시 아르바이트생이에요.","JPN":"うちのコンビニで働く臨時バイトです。","ENG":"This is a temp part-timer from our convenience store.","TWN":"她是我們便利商店的臨時工讀生。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"정말인가? 그 점장이 아르바이트생을?","JPN":"本当に？　あの店長がバイトを雇ったって？","ENG":"Really? The manager actually hired someone?","TWN":"真的嗎？那個店長把工讀生…？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"그게 말이죠~","JPN":"それがですね～。","ENG":"It’s a long story...","TWN":"那是因為～"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"안녕하세요! 유통기한 지난 샌드위치 받으러 왔습니다!","JPN":"こんにちは！　賞味期限切れのサンドイッチをもらいに来ました！","ENG":"Hi! We’re here to retrieve the expired sandwiches!","TWN":"你好！我來拿過期的三明治！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"오, 오늘은…… 라면도 있을 거라고 기대하고 있어요.","JPN":"きょ、今日は……カップ麵もあると期待しています。","ENG":"I-I was hoping maybe... you’d have some noodles as well.","TWN":"聽…聽說… 今天還會有泡麵，好期待。 "},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"손님, 유통기한 지난 식품은 팔 수가 없어요. 무료로 드릴 수도 없고요.","JPN":"お客様、賞味期限が過ぎた食品は販売できません。タダで差し上げることもできません。","ENG":"I’m sorry, I’m not allowed to sell expired goods. I can’t just give them away either.","TWN":"這位客人，我們不能賣過期的食品，也不能把報廢免費送給你。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"그리고 지난달 외상 아직 안 갚으셨잖아요. 점장님도 그것 때문에 많이 화나셨어요.","JPN":"そして先月分のツケがまだでしょう。店長もそれでかなり怒っていましたよ。","ENG":"Plus, you haven’t paid your tab from last month yet. The manager is upset.","TWN":"還有上個月賒的帳還沒清呢，店長因為這件事很生氣。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그래서 이렇게 점장님 안 계실 때 온 거죠!","JPN":"だからこうして店長がいない時に来たんですよ！","ENG":"That’s why we’re here now, while your manager is out!","TWN":"所以我才趁店長不在的時候過來啊！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"흐흑……. 밥벌레라 죄송합니다…….","JPN":"ぐすん……毎回すみません……","ENG":"*Sob...* I’m sorry I’m good for nothing...","TWN":"嗚嗚… 我是米蟲，真抱歉…"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"울어도 안 돼요. 한 번 더 그러면 저도 자르겠다고 하셨거든요.","JPN":"泣いてもダメです。もう一回やったら私も首にすると言われてしまったので。","ENG":"Crying won’t help you. The manager is going to fire me if I help you one more time.","TWN":"你哭也沒用，店長說下次再這樣就要我滾。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히로세 씨……. 결국 마지막 편의점마저 우리한테 등을 돌렸네요…….","JPN":"廣瀬さん……最後のコンビニまで私たちを見捨ててしまいました……","ENG":"Aki... Our last resort has finally turned on us...","TWN":"廣瀨…連最後的便利商店也拋棄我們了…"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어째서! 귀여운 미소녀들 부탁을 들어 주는 건 민서네 업계에선 포상이라면서요!","JPN":"なんで！　可愛い美少女のお願いを聞いてあげるのはヒミコさんの業界ではご褒美と言ってたじゃないですか！","ENG":"Why? I heard that helping cute girls is a gift in your industry!","TWN":"怎麼會！不是說接受可愛美少女的請求是業界的獎勵嗎！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히로세 씨나 저는 R등급 귀여움인 걸요……. SR과 넘을 수 없는 격차가 있어요…….","JPN":"廣瀬さんもヒミコもRランクの可愛さですもん……SRとは超えられない壁があります……","ENG":"Aki, we both are Grade R cute girls... There is a huge gap between R and SR...","TWN":"廣瀨和我都是只是R級的可愛…上不去SR級…"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"친구들, 식량을 구해 온다면서 왜 이리 늦는 건가?","JPN":"諸君、食料を調達してくると言っていたがなぜこんなに遅いんだ？","ENG":"Friends, you said you were getting food. What’s taking you so long?","TWN":"朋友們，不是說要拿糧食回來嗎？怎麼這麼慢？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"글쎄, 외상을 갚지 못하면 어림도 없대요.","JPN":"それが、ツケを払わないともうダメらしいです。","ENG":"Um, they are not giving us anything until we pick up our tab.","TWN":"這個嘛，說是要先把賒的帳清一清。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"다 틀렸어요……. 이제 저희한테는 겨울날 눈 맞으면서 동사하는 엔딩뿐이에요…….","JPN":"もう生きていけません……私たちに残されたのは、冬の日に雪に埋もれて餓死か凍死エンドだけです……","ENG":"It’s all for nothing... The only ending for us is to die miserably in the middle of a snowy day...","TWN":"我們GG了…我們的結局就是在下著雪的冬天冷死吧……"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"뭐야, 그런 거였나.","JPN":"なんだ、そういうことか。","ENG":"Oh, I see.","TWN":"什麼嘛，原來是這樣？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"나한테 맡겨. 설산에서 우리가 쌓은 우정이 돈 몇 푼에 얼어붙게 할 수는 없지.","JPN":"私に任せろ。雪山で築いた友情を金ごときで失うわけにはいかない。","ENG":"Leave it to me. I can’t let our friendship, formed atop the snowy mountain, grow cold over some coins.","TWN":"交給我吧！我們在雪山積累的友情，不能因爲幾毛錢就融化了！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"점원, 총잡이 한 명 고용할 생각 없나?","JPN":"なあ、店員。ガンナーを雇用する気はないか？","ENG":"Hey, part-timer. Interested in hiring a gunslinger?","TWN":"店員，店裡有缺神槍手嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"아, 점장님이 며칠 쉬는 동안 임시 아르바이트생 구한다고 하시던데 그쪽이셨구나♪","JPN":"あ、店長さんが数日休みを取る間、臨時のバイトを雇うと言っていましたが、あなただったんですね♪","ENG":"Oh, the manager told me we’re hiring a temp part-timer, that must be you.","TWN":"哦～店長說他休假的這段時間，有找一個臨時工讀生來代替他，原來就是你喔♪"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"제가 일 잘 가르쳐 드릴게요. 우선 유니폼으로 갈아입게 저쪽으로 가실래요?","JPN":"私が一から丁寧に教えますね。まずはユニフォームに着替えてくださいますか？","ENG":"Let me help you. First, let’s go over there so that you can change into your uniform.","TWN":"我會好好帶著你做的，先去那邊換制服吧！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗훗. 그래, 이런 공공연한 장소에서 실력을 보여선 곤란하지.","JPN":"フッフッフッ。そうだな、こんな公の場で実力を見せるのは困るだろうな。","ENG":"Heh heh heh. You’re right, I can’t start a gunfight in public.","TWN":"呵呵呵，也是，怎麼能在大庭廣眾之下展現實力呢！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"크흑……! 한 몸 바쳐 굶주린 우리에게 먹을 걸 주다니……!","JPN":"くふっ……！　自ら身を捧げて秋たちに食べ物を与えるなんて……！","ENG":"Ah! She’s sacrificing herself to feed us!","TWN":"嗚…！竟然給餓壞的我們東西吃………！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"왠지, 멋있어 보여요…….","JPN":"なんだか、カッコイイです……","ENG":"She’s so awesome...","TWN":"突然覺得好帥…"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"……그런데 저 분, 딱히 프리덤 라이더에 받아준 적 없었던 것 같은데요.","JPN":"……ところであの方、フリーダム・ライダーズが受け入れた覚えがありませんね。","ENG":"... By the way, I don't remember accepting her as a Freedom Rider.","TWN":"……不過，我們好像沒有同意她住進來吧。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그러게요. 언젠가부터 꼭 자기 집처럼 눌러앉아 있네요.","JPN":"そうですね。いつからか、自分の家みたいに居座っていますね。","ENG":"I know. And she's been staying here as if it's her home.","TWN":"就是說啊，他就這樣默默把這裡當自己家。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"희린 씨를 통해 확인했습니다. 원래 호출하신 타이탄은 코핀함과 함께 점검 중이라더군요.","JPN":"キタハラ課長に確認しました。呼び出したタイタンはコフィン艦と一緒に点検中だそうです。","ENG":"I’ve talked to Heerin. Titan, whom you initially requested for, is currently under repairs, along with the Coffin ship.","TWN":"和喜琳確認過了，老闆原本找的泰坦，現在正和科芬艦一起維修中。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"맞아. 정비사 언니가 할아버지한테 모래 들어가면 청소하기 어렵다고 했어.","JPN":"そうだよ。整備士のお姉ちゃんがおじいちゃんに砂が入ったら掃除が大変と言ってたの。","ENG":"Yes, the mechanic lady said it’s hard to clean up Grandpa when sand gets into his body.","TWN":"對了，維修員姊姊說，爺爺進沙的話會很難清理。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그래도 괜찮아, 아빠! 내가 할아버지 몫까지 힘낼게!","JPN":"でも大丈夫だよ、パパ！　私がおじいちゃんの分まで頑張るから！","ENG":"It’s okay, Daddy! I’ll do my best on behalf of Grandpa!","TWN":"沒關係啦，爸爸！我會連爺爺的份一起努力的！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음. 그렇다면야 이 인원으로 가는 수밖에.","JPN":"うむ。ならばこのメンツで行くしかないか。","ENG":"Well, then we’ll have to proceed with this crew.","TWN":"嗯，也只能這樣囉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어흠, 우리 딸한테는 중요한 할일이 있어요.","JPN":"コホン、うちの子には大事な仕事があります。","ENG":"Hm, my dear daughter, you have a very important job to do.","TWN":"咳咳，爸爸有重要的任務要交給女兒。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"진짜? 뭔데? 뭔데?","JPN":"ホントに？　なになに？","ENG":"Really? What is it? What is it?","TWN":"真的嗎？什麼什麼？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"바로바로~ 홍보 담당이지!","JPN":"それはなんと、広報担当だ！","ENG":"You will be our PR manager!","TWN":"那就是～負責宣傳！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"만세! 난 이제부터 홍보 담당이야!","JPN":"やったあ！　私はこれから広報担当だよ！","ENG":"Yay! I’m a PR manager!","TWN":"萬歲！從現在開始我負責宣傳喔！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그런데 홍보 담당은 뭘 하면 돼?","JPN":"ところで広報担当は何をすればいいの？","ENG":"What does a PR manager do?","TWN":"不過負責宣傳的要做什麼呢？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아주 간단해. 저 펭귄들과 바다에서 신나게 노는 거란다.","JPN":"とても簡単さ。あのペンギンたちと海で楽しく遊ぶだけだよ。","ENG":"It’s simple. Go play with those penguins on the beach.","TWN":"很簡單～只需要和那些企鵝一起開心地在海邊玩。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오, 정말? 무지 재밌겠다!","JPN":"おお、本当に？　楽しそう！","ENG":"Wow, really? That sounds so much fun!","TWN":"喔喔！真的嗎？好像很好玩喔！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"알았어, 아빠! 나 열심히 신나게 놀게!","JPN":"わかった、パパ！　頑張って楽しく遊ぶね！","ENG":"Okay, Daddy! I’ll do my best playing with the penguins!","TWN":"沒問題，爸爸！我會努力認真玩的！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"모네 양도 같이 가서 즐기게나.","JPN":"モネも一緒に行って楽しんでいいぞ。","ENG":"Mone, you go ahead and have fun with them as well.","TWN":"莫妮也一起去玩吧。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"넵? 모네도 말이심까?","JPN":"え？　モネも行っていいっすか？","ENG":"Oh, Mone too, sir?","TWN":"嗯？莫妮也一起嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"사람들은 침식체가 나타났다는 소문만 믿고 오지 않는 걸세.","JPN":"人々は侵食体が現れたという噂だけを信じて来ないわけだ。","ENG":"People are not coming to your village because they heard the rumors about the C.O.s.","TWN":"大家是因為侵蝕體出現的傳言才不來的。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면 여기 있는 펭귄들이 생각만큼 위험하지 않다는 사실부터 알려 줘야지.","JPN":"ならば、ここにいるペンギンたちが危険じゃないという事実から知らせないと。","ENG":"You should show them that these penguins are not as dangerous as one might think.","TWN":"所以首先就是要告訴大家，這裡的企鵝沒有想象中那麼危險。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네들이 펭귄들과 어울리는 모습을 찍어서 넷튜브에 올릴 계획이라네.","JPN":"君たちがペンギンたちと戯れる様子を撮って、ネットチューブにアップするつもりだ。","ENG":"We’ll be recording you having fun with these penguins and upload it on NetTube.","TWN":"我的計畫是拍下你們和企鵝玩得很開心的樣子，再上傳到社群平台。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"오오……! 주인님은 정말 속이 깊으시지 말임다!","JPN":"おお……！　ご主人様は本当に頭がいいっすね！","ENG":"Oh! You’re so considerate, sir!","TWN":"哦哦…！主人想得很周到呢！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그러면 마을을 위해 모네도 사양 않고 다녀오겠슴다!","JPN":"それでは村のためにモネも喜んで行ってくるっす！","ENG":"Then Mone will go have fun with the penguins, sir!","TWN":"爲了村子好，那我也一起去玩囉！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"훗훗훗. 총잡이인 내게 어울리는 일감은 아니로군.","JPN":"フッフッフッ。ガンナーの私に似合う仕事ではないな。","ENG":"Heh heh heh. This doesn’t look like a job for a gunslinger like me.","TWN":"呵呵呵，這種事感覺不太適合我這個神槍手。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"해변의 질서를 짓밟는 무법자들을 처단하는 것이야말로……","JPN":"海辺の秩序を踏みにじる無法者を成敗することこそ……","ENG":"My true calling is to punish outlaws who disturb the laws of the beach...","TWN":"我要做的應該是懲罰破壞海邊秩序的不法分子……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":" 엥?","JPN":"え？","ENG":" Huh?","TWN":"嗯？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네?","JPN":"モネ？","ENG":"Mone?","TWN":"莫妮？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님~ 저는 뭘 하면 될까요?","JPN":"社長！　私は何をすればいいですか？","ENG":"Boss, what about me?","TWN":"老闆～那我要做什麼呢？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"팝콘 좀 튀겨다 주겠나?","JPN":"ポップコーンを作ってきてくれないか？","ENG":"Could you get me some popcorn?","TWN":"你可以幫我爆爆米花嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"주문 감사합니다~","JPN":"ご注文ありがとうございま～す！","ENG":"Thank you for your order!","TWN":"謝謝光臨～"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};